import time from openai import OpenAI
def submit_finetune_job(training_file: str, model: str = "gpt-4o-mini-2024-07-18", suffix: str = "v1", n_epochs: int = 3) -> str: client = OpenAI() with open(training_file, "rb") as f: upload = client.files.create(file=f, purpose="fine-tune")
job = client.fine_tuning.jobs.create( training_file=upload.id, model=model, suffix=suffix, hyperparameters={"n_epochs": n_epochs}, )
while job.status not in ("succeeded", "failed", "cancelled"): time.sleep(60) job = client.fine_tuning.jobs.retrieve(job.id)
if job.status == "succeeded": return job.fine_tuned_model raise RuntimeError(f"Fine-tuning failed: {job.error}")
